SELECT * FROM audit_log
WHERE create_time >= #{startTime}
AND create_time <= #{endTime}
ORDER BY create_time DESC

SELECT * FROM audit_log


        AND username = #{request.username}


        AND operation LIKE CONCAT('%', #{request.operation}, '%')


        AND business_type = #{request.businessType}


        AND request_ip = #{request.requestIp}


        AND response_result = #{request.responseResult}


        AND create_time >= #{request.startTime}


        AND create_time <= #{request.endTime}


        AND (operation LIKE CONCAT('%', #{request.keyword}, '%')
        OR username LIKE CONCAT('%', #{request.keyword}, '%')
        OR error_msg LIKE CONCAT('%', #{request.keyword}, '%'))


ORDER BY create_time DESC
LIMIT #{request.size} OFFSET #{request.offset}
